  5→import { globalValue } from "effect/GlobalValue"
  6→import * as Option from "effect/Option"
  7→import * as Queue from "effect/Queue"
  8→import * as Stream from "effect/Stream"
  9→import type * as Atom from "../Atom.js"
 10→import type * as Registry from "../Registry.js"
 11→import * as Result from "../Result.js"
 12→
 13→const constImmediate = { immediate: true }
 14→
 15→const notifyListener = (listener: () => void): void => {
 16→  listener()
 17→}
 18→
 19→type TypeId = "~effect-atom/atom/Registry"
 20→const TypeId: TypeId = "~effect-atom/atom/Registry" as const
 21→
 22→/** @internal */
 23→export const make = (options?: {
 24→  readonly initialValues?: Iterable<readonly [Atom.Atom<any>, any]> | undefined
 25→  readonly scheduleTask?: ((f: () => void) => void) | undefined
 26→  readonly timeoutResolution?: number | undefined
 27→  readonly defaultIdleTTL?: number | undefined
 28→}): Registry.Registry =>
 29→  new RegistryImpl(
 30→    options?.initialValues,
 31→    options?.scheduleTask,
 32→    options?.timeoutResolution,
 33→    options?.defaultIdleTTL
 34→  )
 35→
 36→const SerializableTypeId: Atom.SerializableTypeId = "~effect-atom/atom/Atom/Serializable"
 37→const atomKey = <A>(atom: Atom.Atom<A>): Atom.Atom<A> | string =>
 38→  SerializableTypeId in atom ? (atom as Atom.Serializable<any>)[SerializableTypeId].key : atom
 39→
 40→class RegistryImpl implements Registry.Registry {
 41→  readonly [TypeId]: TypeId
 42→  readonly timeoutResolution: number
 43→
 44→  constructor(
 45→    initialValues?: Iterable<readonly [Atom.Atom<any>, any]>,
 46→    readonly scheduleTask = (cb: () => void): void => queueMicrotask(cb),
 47→    timeoutResolution?: number,
 48→    readonly defaultIdleTTL?: number
 49→  ) {
 50→    this[TypeId] = TypeId
 51→    if (timeoutResolution === undefined && defaultIdleTTL !== undefined) {
 52→      this.timeoutResolution = Math.round(defaultIdleTTL / 2)
 53→    } else {
 54→      this.timeoutResolution = timeoutResolution ?? 1000
 55→    }
 56→    if (initialValues !== undefined) {
 57→      for (const [atom, value] of initialValues) {
 58→        this.ensureNode(atom).setValue(value)
 59→      }
 60→    }
 61→  }
 62→
 63→  readonly nodes = new Map<Atom.Atom<any> | string, Node<any>>()
 64→  readonly preloadedSerializable = new Map<string, unknown>()
 65→  readonly timeoutBuckets = new Map<number, readonly [nodes: Set<Node<any>>, handle: number]>()
 66→  readonly nodeTimeoutBucket = new Map<Node<any>, number>()
 67→  disposed = false
 68→
 69→  getNodes() {
 70→    return this.nodes
 71→  }
 72→
 73→  get<A>(atom: Atom.Atom<A>): A {
 74→    return this.ensureNode(atom).value()
 75→  }
 76→
 77→  set<R, W>(atom: Atom.Writable<R, W>, value: W): void {
 78→    atom.write(this.ensureNode(atom).writeContext, value)
 79→  }
 80→
 81→  setSerializable(key: string, encoded: unknown): void {
 82→    this.preloadedSerializable.set(key, encoded)
 83→  }
 84→
 85→  modify<R, W, A>(atom: Atom.Writable<R, W>, f: (_: R) => [returnValue: A, nextValue: W]): A {
 86→    const node = this.ensureNode(atom)
 87→    const result = f(node.value())
 88→    atom.write(node.writeContext, result[1])
 89→    return result[0]
 90→  }
 91→
 92→  update<R, W>(atom: Atom.Writable<R, W>, f: (_: R) => W): void {
 93→    const node = this.ensureNode(atom)
 94→    atom.write(node.writeContext, f(node.value()))
 95→  }
 96→
 97→  refresh = <A>(atom: Atom.Atom<A>): void => {
 98→    if (atom.refresh !== undefined) {
 99→      atom.refresh(this.refresh)
100→    } else {
101→      this.invalidateAtom(atom)
102→    }
103→  }
104→
105→  subscribe<A>(atom: Atom.Atom<A>, f: (_: A) => void, options?: { readonly immediate?: boolean }): () => void {
106→    const node = this.ensureNode(atom)
107→    if (options?.immediate) {
108→      f(node.value())
109→    }
110→    const remove = node.subscribe(function() {
111→      f(node._value)
112→    })
113→    return () => {
114→      remove()
115→      if (node.canBeRemoved) {
116→        this.scheduleNodeRemoval(node)
117→      }
118→    }
119→  }
120→
121→  mount<A>(atom: Atom.Atom<A>) {
122→    return this.subscribe(atom, constVoid, constImmediate)
123→  }
124→
125→  atomHasTtl(atom: Atom.Atom<any>): boolean {
126→    return !atom.keepAlive && atom.idleTTL !== 0 && (atom.idleTTL !== undefined || this.defaultIdleTTL !== undefined)
127→  }
128→
129→  ensureNode<A>(atom: Atom.Atom<A>): Node<A> {
130→    const key = atomKey(atom)
131→    let node = this.nodes.get(key)
132→    if (node === undefined) {
133→      node = this.createNode(atom)
134→      this.nodes.set(key, node)
135→    } else if (this.atomHasTtl(atom)) {
136→      this.removeNodeTimeout(node)
137→    }
138→    if (typeof key === "string" && this.preloadedSerializable.has(key)) {
139→      const encoded = this.preloadedSerializable.get(key)
140→      this.preloadedSerializable.delete(key)
141→      const decoded = (atom as any as Atom.Serializable<any>)[SerializableTypeId].decode(encoded)
142→      node.setValue(decoded)
143→    }
144→    return node
145→  }
146→
147→  createNode<A>(atom: Atom.Atom<A>): Node<A> {
148→    if (this.disposed) {
149→      throw new Error(`Cannot access Atom ${atom}: registry is disposed`)
150→    }
151→
152→    if (!atom.keepAlive) {
153→      this.scheduleAtomRemoval(atom)
154→    }
155→    return new Node(this, atom)
156→  }
157→
158→  invalidateAtom = <A>(atom: Atom.Atom<A>): void => {
159→    this.ensureNode(atom).invalidate()
160→  }
161→
162→  scheduleAtomRemoval(atom: Atom.Atom<any>): void {
163→    this.scheduleTask(() => {
164→      const node = this.nodes.get(atomKey(atom))
165→      if (node !== undefined && node.canBeRemoved) {
166→        this.removeNode(node)
167→      }
168→    })
169→  }
170→
171→  scheduleNodeRemoval(node: Node<any>): void {
172→    this.scheduleTask(() => {
173→      if (node.canBeRemoved) {
174→        this.removeNode(node)
175→      }
176→    })
177→  }
178→
179→  removeNode(node: Node<any>): void {
180→    if (this.atomHasTtl(node.atom)) {
181→      this.setNodeTimeout(node)
182→    } else {
183→      this.nodes.delete(atomKey(node.atom))
184→      node.remove()
185→    }
186→  }
187→
188→  setNodeTimeout(node: Node<any>): void {
189→    if (this.nodeTimeoutBucket.has(node)) {
190→      return
191→    }
192→
193→    let idleTTL = node.atom.idleTTL ?? this.defaultIdleTTL!
194→    if (this.#currentSweepTTL !== null) {
195→      idleTTL -= this.#currentSweepTTL
196→      if (idleTTL <= 0) {
197→        this.nodes.delete(atomKey(node.atom))
198→        node.remove()
199→        return
200→      }
201→    }
202→    const ttl = Math.ceil(idleTTL! / this.timeoutResolution) * this.timeoutResolution
203→    const timestamp = Date.now() + ttl
204→    const bucket = timestamp - (timestamp % this.timeoutResolution) + this.timeoutResolution
205→
206→    let entry = this.timeoutBuckets.get(bucket)
207→    if (entry === undefined) {
208→      entry = [
209→        new Set<Node<any>>(),
210→        setTimeout(() => this.sweepBucket(bucket), bucket - Date.now())
211→      ]
212→      this.timeoutBuckets.set(bucket, entry)
213→    }
214→    entry[0].add(node)
215→    this.nodeTimeoutBucket.set(node, bucket)
216→  }
217→
218→  removeNodeTimeout(node: Node<any>): void {
219→    const bucket = this.nodeTimeoutBucket.get(node)
220→    if (bucket === undefined) {
221→      return
222→    }
223→    this.nodeTimeoutBucket.delete(node)
224→    this.scheduleNodeRemoval(node)
225→
226→    const [nodes, handle] = this.timeoutBuckets.get(bucket)!
227→    nodes.delete(node)
228→    if (nodes.size === 0) {
229→      clearTimeout(handle)
230→      this.timeoutBuckets.delete(bucket)
231→    }
232→  }
233→
234→  #currentSweepTTL: number | null = null
235→  sweepBucket(bucket: number): void {
236→    const nodes = this.timeoutBuckets.get(bucket)![0]
237→    this.timeoutBuckets.delete(bucket)
238→
239→    nodes.forEach((node) => {
240→      if (!node.canBeRemoved) {
241→        return
242→      }
243→      this.nodeTimeoutBucket.delete(node)
244→      this.nodes.delete(atomKey(node.atom))
245→      this.#currentSweepTTL = node.atom.idleTTL ?? this.defaultIdleTTL!
246→      node.remove()
247→      this.#currentSweepTTL = null
248→    })
249→  }
250→
251→  reset(): void {
252→    this.timeoutBuckets.forEach(([, handle]) => clearTimeout(handle))
253→    this.timeoutBuckets.clear()
254→    this.nodeTimeoutBucket.clear()
255→
256→    this.nodes.forEach((node) => node.remove())
257→    this.nodes.clear()
258→  }
259→
260→  dispose(): void {
261→    this.disposed = true
262→    this.reset()
263→  }
264→}
265→
266→const enum NodeFlags {
267→  alive = 1 << 0,
268→  initialized = 1 << 1,
269→  waitingForValue = 1 << 2
270→}
271→
272→const enum NodeState {
273→  uninitialized = NodeFlags.alive | NodeFlags.waitingForValue,
274→  stale = NodeFlags.alive | NodeFlags.initialized | NodeFlags.waitingForValue,
275→  valid = NodeFlags.alive | NodeFlags.initialized,
276→  removed = 0
277→}
278→
279→class Node<A> {
280→  constructor(
281→    readonly registry: RegistryImpl,
282→    readonly atom: Atom.Atom<A>
283→  ) {
284→    this.writeContext = new WriteContextImpl(registry, this)
285→  }
286→
287→  state: NodeState = NodeState.uninitialized
288→  lifetime: Lifetime<A> | undefined
289→  writeContext: WriteContextImpl<A>
290→
291→  parents: Array<Node<any>> = []
292→  previousParents: Array<Node<any>> | undefined
293→  children: Array<Node<any>> = []
294→  listeners: Set<() => void> = new Set()
295→  skipInvalidation = false
296→
297→  get canBeRemoved(): boolean {
298→    return !this.atom.keepAlive && this.listeners.size === 0 && this.children.length === 0 &&
299→      this.state !== 0
300→  }
301→
302→  _value: A = undefined as any
303→  value(): A {
304→    if ((this.state & NodeFlags.waitingForValue) !== 0) {
305→      this.lifetime = makeLifetime(this)
306→      const value = this.atom.read(this.lifetime)
307→      if ((this.state & NodeFlags.waitingForValue) !== 0) {
308→        this.setValue(value)
309→      }
310→
311→      if (this.previousParents) {
312→        const parents = this.previousParents
313→        this.previousParents = undefined
314→        for (let i = 0; i < parents.length; i++) {
315→          parents[i].removeChild(this)
316→          if (parents[i].canBeRemoved) {
317→            this.registry.scheduleNodeRemoval(parents[i])
318→          }
319→        }
320→      }
321→    }
322→
323→    return this._value
324→  }
325→
326→  valueOption(): Option.Option<A> {
327→    if ((this.state & NodeFlags.initialized) === 0) {
328→      return Option.none()
329→    }
330→    return Option.some(this._value)
331→  }
332→
333→  setValue(value: A): void {
334→    if ((this.state & NodeFlags.initialized) === 0) {
335→      this.state = NodeState.valid
336→      this._value = value
337→
338→      if (batchState.phase === BatchPhase.collect) {
339→        batchState.notify.add(this)
340→      } else {
341→        this.notify()
342→      }
343→
344→      return
345→    }
346→
347→    this.state = NodeState.valid
348→    if (Equal.equals(this._value, value)) {
349→      return
350→    }
351→
352→    this._value = value
353→    if (this.skipInvalidation) {
354→      this.skipInvalidation = false
355→    } else {
356→      this.invalidateChildren()
357→    }
358→
359→    if (this.listeners.size > 0) {
360→      if (batchState.phase === BatchPhase.collect) {
361→        batchState.notify.add(this)
362→      } else {
363→        this.notify()
364→      }
365→    }
366→  }
367→
368→  addParent(parent: Node<any>): void {
369→    this.parents.push(parent)
370→    if (this.previousParents !== undefined) {
371→      const index = this.previousParents.indexOf(parent)
372→      if (index !== -1) {
373→        this.previousParents[index] = this.previousParents[this.previousParents.length - 1]
374→        if (this.previousParents.pop() === undefined) {
375→          this.previousParents = undefined
376→        }
377→      }
378→    }
379→
380→    if (parent.children.indexOf(this) === -1) {
381→      parent.children.push(this)
382→      if (parent.skipInvalidation) {
383→        parent.skipInvalidation = false
384→      }
385→    }
386→  }
387→
388→  removeChild(child: Node<any>): void {
389→    const index = this.children.indexOf(child)
390→    if (index !== -1) {
391→      this.children[index] = this.children[this.children.length - 1]
392→      this.children.pop()
393→    }
394→  }
395→
396→  invalidate(): void {
397→    if (this.state === NodeState.valid) {
398→      this.state = NodeState.stale
399→      this.disposeLifetime()
400→    }
401→
402→    if (batchState.phase === BatchPhase.collect) {
403→      batchState.stale.push(this)
404→    } else if (this.atom.lazy && this.listeners.size === 0 && !childrenAreActive(this.children)) {
405→      this.invalidateChildren()
406→      this.skipInvalidation = true
407→    } else {
408→      this.value()
409→    }
410→  }
411→
412→  invalidateChildren(): void {
413→    if (this.children.length === 0) {
414→      return
415→    }
416→
417→    const children = this.children
418→    this.children = []
419→    for (let i = 0; i < children.length; i++) {
420→      children[i].invalidate()
421→    }
422→  }
423→
424→  notify(): void {
425→    this.listeners.forEach(notifyListener)
426→
427→    if (batchState.phase === BatchPhase.commit) {
428→      batchState.notify.delete(this)
429→    }
430→  }
431→
432→  disposeLifetime(): void {
433→    if (this.lifetime !== undefined) {
434→      this.lifetime.dispose()
435→      this.lifetime = undefined
436→    }
437→
438→    if (this.parents.length !== 0) {
439→      this.previousParents = this.parents
440→      this.parents = []
441→    }
442→  }
443→
444→  remove() {
445→    this.state = NodeState.removed
446→    this.listeners.clear()
447→
448→    if (this.lifetime === undefined) {
449→      return
450→    }
451→
452→    this.disposeLifetime()
453→
454→    if (this.previousParents === undefined) {
455→      return
456→    }
457→
458→    const parents = this.previousParents
459→    this.previousParents = undefined
460→    for (let i = 0; i < parents.length; i++) {
461→      parents[i].removeChild(this)
462→      if (parents[i].canBeRemoved) {
463→        this.registry.removeNode(parents[i])
464→      }
465→    }
466→  }
467→
468→  subscribe(listener: () => void): () => void {
469→    this.listeners.add(listener)
470→    return () => this.listeners.delete(listener)
471→  }
472→}
473→
474→function childrenAreActive(children: Array<Node<any>>): boolean {
475→  if (children.length === 0) {
476→    return false
477→  }
478→  let current: Array<Node<any>> | undefined = children
479→  let stack: Array<Array<Node<any>>> | undefined
480→  let stackIndex = 0
481→  while (current !== undefined) {
482→    for (let i = 0, len = current.length; i < len; i++) {
483→      const child = current[i]
484→      if (!child.atom.lazy || child.listeners.size > 0) {
485→        return true
486→      } else if (child.children.length > 0) {
487→        if (stack === undefined) {
488→          stack = [child.children]
489→        } else {
490→          stack.push(child.children)
491→        }
492→      }
493→    }
494→    current = stack?.[stackIndex++]
495→  }
496→  return false
497→}
498→
499→interface Lifetime<A> extends Atom.Context {
500→  isFn: boolean
501→  readonly node: Node<A>
502→  finalizers: Array<() => void> | undefined
503→  disposed: boolean
504→  readonly dispose: () => void
505→}
506→
507→const disposedError = (atom: Atom.Atom<any>): Error => new Error(`Cannot use context of disposed Atom: ${atom}`)
508→
509→const LifetimeProto: Omit<Lifetime<any>, "node" | "finalizers" | "disposed" | "isFn"> = {
510→  get registry(): RegistryImpl {
511→    return (this as Lifetime<any>).node.registry
512→  },
513→
514→  addFinalizer(this: Lifetime<any>, f: () => void): void {
515→    if (this.disposed) {
516→      throw disposedError(this.node.atom)
517→    }
518→    this.finalizers ??= []
519→    this.finalizers.push(f)
520→  },
521→
522→  get<A>(this: Lifetime<any>, atom: Atom.Atom<A>): A {
523→    if (this.disposed) {
524→      throw disposedError(this.node.atom)
525→    }
526→    const parent = this.node.registry.ensureNode(atom)
527→    this.node.addParent(parent)
528→    return parent.value()
529→  },
530→
531→  result<A, E>(this: Lifetime<any>, atom: Atom.Atom<Result.Result<A, E>>, options?: {
532→    readonly suspendOnWaiting?: boolean | undefined
533→  }): Effect.Effect<A, E> {
534→    if (this.disposed) {
535→      throw disposedError(this.node.atom)
536→    } else if (this.isFn) {
537→      return this.resultOnce(atom, options)
538→    }
539→    const result = this.get(atom)
540→    if (options?.suspendOnWaiting && result.waiting) {
541→      return Effect.never
542→    }
543→    switch (result._tag) {
544→      case "Initial": {
545→        return Effect.never
546→      }
547→      case "Failure": {
548→        return Exit.failCause(result.cause)
549→      }
550→      case "Success": {
551→        return Effect.succeed(result.value)
552→      }
553→    }
554→  },
555→
556→  resultOnce<A, E>(this: Lifetime<any>, atom: Atom.Atom<Result.Result<A, E>>, options?: {
557→    readonly suspendOnWaiting?: boolean | undefined
558→  }): Effect.Effect<A, E> {
559→    if (this.disposed) {
560→      throw disposedError(this.node.atom)
561→    }
562→    return Effect.async<A, E>((resume) => {
563→      const result = this.once(atom)
564→      if (result._tag !== "Initial" && !(options?.suspendOnWaiting && result.waiting)) {
565→        return resume(Result.toExit(result) as any)
566→      }
567→      const cancel = this.node.registry.subscribe(atom, (result) => {
568→        if (result._tag === "Initial" || (options?.suspendOnWaiting && result.waiting)) return
569→        cancel()
570→        resume(Result.toExit(result) as any)
571→      }, { immediate: false })
572→      return Effect.sync(cancel)
573→    })
574→  },
575→
576→  setResult<A, E, W>(this: Lifetime<any>, atom: Atom.Writable<Result.Result<A, E>, W>, value: W): Effect.Effect<A, E> {
577→    if (this.disposed) {
578→      throw disposedError(this.node.atom)
579→    }
580→    this.node.registry.set(atom, value)
581→    return this.resultOnce(atom, { suspendOnWaiting: true })
582→  },
583→
584→  some<A>(this: Lifetime<any>, atom: Atom.Atom<Option.Option<A>>): Effect.Effect<A> {
585→    if (this.disposed) {
586→      throw disposedError(this.node.atom)
587→    } else if (this.isFn) {
588→      return this.someOnce(atom)
589→    }
590→    const result = this.get(atom)
591→    return result._tag === "None" ? Effect.never : Effect.succeed(result.value)
592→  },
593→
594→  someOnce<A>(this: Lifetime<any>, atom: Atom.Atom<Option.Option<A>>): Effect.Effect<A> {
595→    if (this.disposed) {
596→      throw disposedError(this.node.atom)
597→    }
598→    return Effect.async<A>((resume) => {
599→      const result = this.once(atom)
600→      if (Option.isSome(result)) {
601→        return resume(Effect.succeed(result.value))
602→      }
603→      const cancel = this.node.registry.subscribe(atom, (result) => {
604→        if (Option.isNone(result)) return
605→        cancel()
606→        resume(Effect.succeed(result.value))
607→      }, { immediate: false })
608→      return Effect.sync(cancel)
609→    })
610→  },
611→
612→  once<A>(this: Lifetime<any>, atom: Atom.Atom<A>): A {
613→    if (this.disposed) {
614→      throw disposedError(this.node.atom)
615→    }
616→    return this.node.registry.get(atom)
617→  },
618→
619→  self<A>(this: Lifetime<any>): Option.Option<A> {
620→    if (this.disposed) {
621→      throw disposedError(this.node.atom)
622→    }
623→    return this.node.valueOption() as any
624→  },
625→
626→  refresh<A>(this: Lifetime<any>, atom: Atom.Atom<A>): void {
627→    if (this.disposed) {
628→      throw disposedError(this.node.atom)
629→    }
630→    this.node.registry.refresh(atom)
631→  },
632→
633→  refreshSelf(this: Lifetime<any>): void {
634→    if (this.disposed) {
635→      throw disposedError(this.node.atom)
636→    }
637→    this.node.invalidate()
638→  },
639→
640→  mount<A>(this: Lifetime<any>, atom: Atom.Atom<A>): void {
641→    if (this.disposed) {
642→      throw disposedError(this.node.atom)
643→    }
644→    this.addFinalizer(this.node.registry.mount(atom))
645→  },
646→
647→  subscribe<A>(this: Lifetime<any>, atom: Atom.Atom<A>, f: (_: A) => void, options?: {
648→    readonly immediate?: boolean
649→  }): void {
650→    if (this.disposed) {
651→      throw disposedError(this.node.atom)
652→    }
653→    this.addFinalizer(this.node.registry.subscribe(atom, f, options))
654→  },
655→
656→  setSelf<A>(this: Lifetime<any>, a: A): void {
657→    if (this.disposed) {
658→      throw disposedError(this.node.atom)
659→    }
660→    this.node.setValue(a as any)
661→  },
662→
663→  set<R, W>(this: Lifetime<any>, atom: Atom.Writable<R, W>, value: W): void {
664→    if (this.disposed) {
665→      throw disposedError(this.node.atom)
666→    }
667→    this.node.registry.set(atom, value)
668→  },
669→
670→  stream<A>(this: Lifetime<any>, atom: Atom.Atom<A>, options?: {
671→    readonly withoutInitialValue?: boolean
672→    readonly bufferSize?: number
673→  }) {
674→    if (this.disposed) {
675→      throw disposedError(this.node.atom)
676→    }
677→
678→    return pipe(
679→      Effect.acquireRelease(
680→        Queue.bounded<A>(options?.bufferSize ?? 16),
681→        Queue.shutdown
682→      ),
683→      Effect.tap((queue) =>
684→        Effect.acquireRelease(
685→          Effect.sync(() => {
686→            return this.node.registry.subscribe(atom, (_) => {
687→              Queue.unsafeOffer(queue, _)
688→            }, { immediate: options?.withoutInitialValue !== true })
689→          }),
690→          (cancel) => Effect.sync(cancel)
691→        )
692→      ),
693→      Effect.map((queue) => Stream.fromQueue(queue)),
694→      Stream.unwrapScoped
695→    )
696→  },
697→
698→  streamResult<A, E>(this: Lifetime<any>, atom: Atom.Atom<Result.Result<A, E>>, options?: {
699→    readonly withoutInitialValue?: boolean
700→    readonly bufferSize?: number
701→  }): Stream.Stream<A, E> {
702→    return pipe(
703→      this.stream(atom, options),
704→      Stream.filter(Result.isNotInitial),
705→      Stream.flatMap((result) =>
706→        result._tag === "Success" ? Stream.succeed(result.value) : Stream.failCause(result.cause)
707→      )
708→    )
709→  },
710→
711→  dispose(this: Lifetime<any>): void {
712→    this.disposed = true
713→    if (this.finalizers === undefined) {
714→      return
715→    }
716→
717→    const finalizers = this.finalizers
718→    this.finalizers = undefined
719→    for (let i = finalizers.length - 1; i >= 0; i--) {
720→      finalizers[i]()
721→    }
722→  }
723→}
724→
725→const makeLifetime = <A>(node: Node<A>): Lifetime<A> => {
726→  function get<A>(atom: Atom.Atom<A>): A {
727→    if (get.disposed) {
728→      throw disposedError(atom)
729→    } else if (get.isFn) {
730→      return node.registry.get(atom)
731→    }
732→    const parent = node.registry.ensureNode(atom)
733→    const value = parent.value()
734→    node.addParent(parent)
735→    return value
736→  }
737→  Object.setPrototypeOf(get, LifetimeProto)
738→  get.isFn = false
739→  get.disposed = false
740→  get.finalizers = undefined
741→  get.node = node
742→  return get as any
743→}
744→
745→class WriteContextImpl<A> implements Atom.WriteContext<A> {
746→  constructor(
747→    readonly registry: RegistryImpl,
748→    readonly node: Node<A>
749→  ) {}
750→  get<A>(atom: Atom.Atom<A>): A {
751→    return this.registry.get(atom)
752→  }
753→  set<R, W>(atom: Atom.Writable<R, W>, value: W) {
754→    return this.registry.set(atom, value)
755→  }
756→  setSelf(value: any) {
757→    return this.node.setValue(value)
758→  }
759→  refreshSelf() {
760→    return this.node.invalidate()
761→  }
762→}
763→
764→// -----------------------------------------------------------------------------
765→// batching
766→// -----------------------------------------------------------------------------
767→
768→/** @internal */
769→export const enum BatchPhase {
770→  disabled,
771→  collect,
772→  commit
773→}
774→
775→/** @internal */
776→export const batchState = globalValue("@effect-atom/atom/Registry/batchState", () => ({
777→  phase: BatchPhase.disabled,
778→  depth: 0,
779→  stale: [] as Array<Node<any>>,
780→  notify: new Set<Node<any>>()
781→}))
782→
783→/** @internal */
784→export function batch(f: () => void): void {
785→  batchState.phase = BatchPhase.collect
786→  batchState.depth++
787→  try {
788→    f()
789→    if (batchState.depth === 1) {
790→      for (let i = 0; i < batchState.stale.length; i++) {
791→        batchRebuildNode(batchState.stale[i])
792→      }
793→      batchState.phase = BatchPhase.commit
794→      for (const node of batchState.notify) {
795→        node.notify()
796→      }
797→      batchState.notify.clear()
798→    }
799→  } finally {
800→    batchState.depth--
801→    if (batchState.depth === 0) {
802→      batchState.phase = BatchPhase.disabled
803→      batchState.stale = []
804→    }
805→  }
806→}
807→
808→function batchRebuildNode(node: Node<any>) {
809→  if (node.state === NodeState.valid) {
810→    return
811→  }
812→
813→  for (let i = 0; i < node.parents.length; i++) {
814→    const parent = node.parents[i]
815→    if (parent.state !== NodeState.valid) {
816→      batchRebuildNode(parent)
817→    }
818→  }
819→
820→  // @ts-ignore
821→  if (node.state !== NodeState.valid) {
822→    node.value()
823→  }
824→}
825→

 1→import * as Data from "effect/Data"
 2→import type { ReadonlyRecord } from "effect/Record"
 3→
 4→export const wrapReactivityKeys = (
 5→  keys: ReadonlyArray<unknown> | ReadonlyRecord<string, ReadonlyArray<unknown>>
 6→) => {
 7→  if (Array.isArray(keys)) {
 8→    return Data.array(keys)
 9→  }
10→  const obj: Record<string, ReadonlyArray<unknown>> = Object.create(Data.Structural.prototype)
11→  for (const key in keys) {
12→    const val = (keys as Record<string, ReadonlyArray<unknown>>)[key]
13→    if (!Array.isArray(val)) continue
14→    obj[key] = Data.array(val)
15→  }
16→  return obj
17→}
18→

 1→/**
 2→ * @since 1.0.0
 3→ */
 4→import { NoSuchElementException } from "effect/Cause"
 5→import type * as Effect from "effect/Effect"
 6→import * as Exit from "effect/Exit"
 7→import * as FiberId from "effect/FiberId"
 8→import * as Runtime from "effect/Runtime"
 9→import { SyncScheduler } from "effect/Scheduler"
10→
11→const fastPath = <R, E, A>(effect: Effect.Effect<A, E, R>): Exit.Exit<A, E> | undefined => {
12→  const op = effect as any
13→  switch (op._tag) {
14→    case "Failure":
15→    case "Success": {
16→      return op
17→    }
18→    case "Left": {
19→      return Exit.fail(op.left)
20→    }
21→    case "Right": {
22→      return Exit.succeed(op.right)
23→    }
24→    case "Some": {
25→      return Exit.succeed(op.value)
26→    }
27→    case "None": {
28→      // @ts-expect-error
29→      return Exit.fail(new NoSuchElementException())
30→    }
31→  }
32→}
33→
34→/** @internal */
35→export const runCallbackSync = <R, ER = never>(runtime: Runtime.Runtime<R>) => {
36→  const runFork = Runtime.runFork(runtime)
37→  return <A, E>(
38→    effect: Effect.Effect<A, E, R>,
39→    onExit: (exit: Exit.Exit<A, E | ER>) => void,
40→    uninterruptible = false
41→  ): (() => void) | undefined => {
42→    const op = fastPath(effect)
43→    if (op) {
44→      onExit(op)
45→      return undefined
46→    }
47→    const scheduler = new SyncScheduler()
48→    const fiberRuntime = runFork(effect, { scheduler })
49→    scheduler.flush()
50→    const result = fiberRuntime.unsafePoll()
51→    if (result) {
52→      onExit(result)
53→      return undefined
54→    }
55→    fiberRuntime.addObserver(onExit)
56→    function cancel() {
57→      fiberRuntime.removeObserver(onExit)
58→      if (!uninterruptible) {
59→        fiberRuntime.unsafeInterruptAsFork(FiberId.none)
60→      }
61→    }
62→    return cancel
63→  }
64→}
65→

