"use client"

import React, { useCallback, useState, useEffect } from "react"
import { useAtomSet } from "@effect-atom/atom-react"
import { networkAtom, NETWORK_STORAGE_KEY } from "@/atoms/starknet"
import { NETWORKS } from "@/config/networks"
import type { NetworkId } from "@/config/networks"
import { ThemeToggle } from "@/components/ThemeToggle"

const NAV_LINKS = [
  { href: "#hero", label: "Home" },
  { href: "#why-starknet", label: "Why Starknet" },
  { href: "#verify", label: "Try It" },
  { href: "#deploy", label: "Deploy" },
] as const

function readStoredNetworkId(): NetworkId {
  try {
    const stored = localStorage.getItem(NETWORK_STORAGE_KEY)
    if (stored === "mainnet" || stored === "sepolia" || stored === "devnet") {
      return stored
    }
  } catch {
    // localStorage unavailable
  }
  return "devnet"
}

export function NavHeader(): React.JSX.Element {
  // Local state drives button rendering immediately on click.
  // The atom is updated in parallel so downstream consumers (AccountDeployFlow)
  // react to the change via their own subscriptions.
  const [networkId, setLocalNetwork] = useState<NetworkId>(readStoredNetworkId)
  const setAtomNetwork = useAtomSet(networkAtom)

  // Sync atom on mount so the atom matches localStorage / local state
  useEffect(() => {
    setAtomNetwork(networkId)
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [])

  const handleNetworkChange = useCallback(
    (id: NetworkId) => {
      setLocalNetwork(id)
      setAtomNetwork(id)
      try {
        localStorage.setItem(NETWORK_STORAGE_KEY, id)
      } catch {
        // localStorage unavailable
      }
    },
    [setAtomNetwork],
  )

  return (
    <header className="glass-nav sticky top-0 z-40">
      <nav
        aria-label="Main navigation"
        className="mx-auto flex max-w-6xl items-center justify-between gap-4 px-4 py-3 sm:px-8 sm:py-4"
      >
        <a href="#hero" className="shrink-0 text-sm font-semibold tracking-tight text-falcon-accent">
          Falcon-512
        </a>
        <ul className="hidden items-center gap-8 md:flex">
          {NAV_LINKS.map((link) => (
            <li key={link.href}>
              <a
                href={link.href}
                className="text-sm text-falcon-text/50 transition-colors duration-200 hover:text-falcon-text"
              >
                {link.label}
              </a>
            </li>
          ))}
        </ul>
        <div className="flex shrink-0 items-center gap-2">
          <div
            className="glass-btn flex items-center rounded-full p-0.5"
            role="group"
            aria-label="Network selection"
          >
            {(["devnet", "sepolia", "mainnet"] as const).map((id) => {
              const isActive = networkId === id
              return (
                <button
                  key={id}
                  onClick={() => handleNetworkChange(id)}
                  aria-pressed={isActive}
                  className={`rounded-full px-2 py-0.5 text-[10px] font-medium transition-all duration-200 sm:px-3 sm:py-1 sm:text-xs ${
                    isActive
                      ? "bg-falcon-accent/20 text-falcon-accent shadow-[inset_0_0_0_1px_rgba(6,182,212,0.3)]"
                      : "text-falcon-text/40 hover:text-falcon-text/70"
                  }`}
                >
                  {NETWORKS[id].name}
                </button>
              )
            })}
          </div>
          <ThemeToggle />
        </div>
      </nav>
    </header>
  )
}

